1	import * as THREE from "three";
2	import { createPlanetView } from "./planetView.js";
3	import { createIslandView } from "./islandView.js";
4	
5	const canvas = document.getElementById("scene");
6	const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
7	renderer.setSize(window.innerWidth, window.innerHeight);
8	renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
9	renderer.toneMapping = THREE.ACESFilmicToneMapping;
10	renderer.toneMappingExposure = 0.92;
11	renderer.outputColorSpace = THREE.SRGBColorSpace;
12	
13	// ---------- shared inspection panel ----------
14	const panel = document.getElementById("panel");
15	const panelTitle = document.getElementById("panel-title");
16	const panelBody = document.getElementById("panel-body");
17	const panelFoot = document.getElementById("panel-foot");
18	
19	function openPanel(frag) {
20	  panelTitle.textContent = frag.title;
21	  panelBody.textContent = frag.body;
22	  panelFoot.textContent = `recover with · ${frag.hint}`;
23	  panel.classList.remove("hidden");
24	}
25	function closePanel() { panel.classList.add("hidden"); }
26	document.getElementById("panel-close").addEventListener("click", closePanel);
27	window.addEventListener("keydown", (e) => { if (e.key === "Escape") closePanel(); });
28	
29	// ---------- background music ----------
30	const bgm = document.getElementById("bgm");
31	const audioPanel = document.getElementById("audio-panel");
32	const audioToggle = document.getElementById("audio-toggle");
33	const audioMute = document.getElementById("audio-mute");
34	const audioVolume = document.getElementById("audio-volume");
35	let userPausedMusic = false;
36	
37	if (bgm && audioPanel && audioToggle && audioMute && audioVolume) {
38	  bgm.volume = Number(audioVolume.value);
39	  bgm.autoplay = true;
40	  bgm.loop = true;
41	
42	  const updateAudioUi = () => {
43	    const playing = !bgm.paused;
44	    const awaitingStart = !playing && !userPausedMusic;
45	    audioPanel.classList.toggle("is-awaiting-start", awaitingStart);
46	    audioToggle.classList.toggle("is-playing", playing);
47	    audioToggle.setAttribute("aria-label", playing ? "Pause music" : "Start music");
48	    audioToggle.title = playing ? "Pause music" : "Start music";
49	    audioMute.classList.toggle("is-muted", bgm.muted || bgm.volume === 0);
50	    audioMute.setAttribute("aria-label", bgm.muted ? "Unmute music" : "Mute music");
51	    audioMute.title = bgm.muted ? "Unmute music" : "Mute music";
52	  };
53	
54	  const tryPlayMusic = () => {
55	    if (userPausedMusic) return;
56	    bgm.play().then(updateAudioUi).catch(updateAudioUi);
57	  };
58	  const removeGestureMusicStart = () => {
59	    for (const eventName of ["pointerdown", "click", "keydown", "touchstart"]) {
60	      window.removeEventListener(eventName, startMusicOnGesture, true);
61	    }
62	  };
63	  const startMusicOnGesture = (event) => {
64	    if (event.target?.closest?.("#audio-panel")) return;
65	    tryPlayMusic();
66	  };
67	
68	  audioToggle.addEventListener("click", () => {
69	    if (bgm.paused) {
70	      userPausedMusic = false;
71	      tryPlayMusic();
72	    } else {
73	      userPausedMusic = true;
74	      bgm.pause();
75	      updateAudioUi();
76	    }
77	  });
78	
79	  audioMute.addEventListener("click", () => {
80	    bgm.muted = !bgm.muted;
81	    updateAudioUi();
82	  });
83	
84	  audioVolume.addEventListener("input", () => {
85	    bgm.volume = Number(audioVolume.value);
86	    if (bgm.volume > 0 && bgm.muted) bgm.muted = false;
87	    updateAudioUi();
88	  });
89	
90	  bgm.addEventListener("play", () => {
91	    removeGestureMusicStart();
92	    updateAudioUi();
93	  });
94	  bgm.addEventListener("pause", updateAudioUi);
95	  bgm.addEventListener("volumechange", updateAudioUi);
96	
97	  for (const eventName of ["pointerdown", "click", "keydown", "touchstart"]) {
98	    window.addEventListener(eventName, startMusicOnGesture, true);
