const panel = document.getElementById("panel");
const panelTitle = document.getElementById("panel-title");
const panelBody = document.getElementById("panel-body");
const panelFoot = document.getElementById("panel-foot");
const ckptOffer = document.getElementById("ckpt-offer");
const ckptDone = document.getElementById("ckpt-done");
const ckptCreate = document.getElementById("ckpt-create");

// The artifact context for the panel that's currently open. islandView hands us
// the fragment plus how to mark it checkpointed and how to read overall progress.
let panelCtx = null;

function renderFoot(progress) {
  if (!progress) { panelFoot.textContent = "memory fragment"; return; }
  const { recovered, total } = progress;
  panelFoot.textContent = recovered >= total
    ? "all core memories restored · the ship remembers itself"
    : `core memories restored · ${recovered}/${total}`;
}

function showCheckpointState(saved) {
  ckptOffer.classList.toggle("hidden", saved);
  ckptDone.classList.toggle("hidden", !saved);
}

function openPanel(frag, ctx = {}) {
  panelCtx = ctx;
  panelTitle.textContent = frag.title;
  panelBody.textContent = frag.body;
  showCheckpointState(!!ctx.checkpointed);
  renderFoot(ctx.progress);
  panel.classList.remove("hidden");
}
function closePanel() { panel.classList.add("hidden"); }

// Create a checkpoint for the artifact in the open panel: lock the memory in,
// then flip the panel to its "saved" state and update the progress counter.
ckptCreate?.addEventListener("click", () => {
  if (!panelCtx?.onCreate) return;
  const progress = panelCtx.onCreate();
  panelCtx.checkpointed = true;
  showCheckpointState(true);
  renderFoot(progress);
});

