/* Checkpoint offer inside the inspection panel */
#panel-checkpoint {
  margin-top: 26px;
  padding-top: 22px;
  border-top: 1px solid rgba(111, 227, 255, 0.18);
}

.ckpt-q {
  font-size: 13px;
  letter-spacing: 0.04em;
  color: var(--accent);
  margin-bottom: 10px;
}

.ckpt-explainer {
  font-size: 13px;
  line-height: 1.65;
  opacity: 0.78;
  margin-bottom: 18px;
}

.ckpt-explainer strong {
  color: var(--ink);
  opacity: 1;
  font-weight: 600;
}

#ckpt-create {
  width: 100%;
  padding: 13px 16px;
  font: inherit;
  font-size: 12px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #04121c;
  background: var(--accent);
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.2s ease;
  box-shadow: 0 6px 22px rgba(111, 227, 255, 0.28);
}

#ckpt-create:hover {
  transform: translateY(-1px);
  box-shadow: 0 10px 30px rgba(111, 227, 255, 0.42);
}

#ckpt-create:active { transform: translateY(0); }

#ckpt-done {
  display: flex;
  align-items: center;
  gap: 14px;
}

.ckpt-check {
  flex: none;
  width: 34px;
  height: 34px;
  display: grid;
  place-items: center;
  border-radius: 50%;
  background: rgba(111, 227, 255, 0.16);
  border: 1px solid var(--accent);
  color: var(--accent);
  font-size: 16px;
}

.ckpt-done-title { font-size: 14px; letter-spacing: 0.04em; }
.ckpt-done-sub { font-size: 12px; opacity: 0.6; margin-top: 3px; }

#panel-close {
  position: absolute;
  top: 26px;
  right: 28px;

