:root {
  --accent: #6fe3ff;
  --accent-warm: #ffb86b;
  --ink: #e8f4ff;
  --panel-bg: rgba(8, 14, 26, 0.82);
  --pin-shell: #171126;
  --pin-rim: rgba(255, 244, 232, 0.96);
  --pin-core: #d79e3a;
  --pin-shadow: rgba(2, 4, 10, 0.72);
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #02040a;
  color: var(--ink);
  font-family: "SF Mono", "JetBrains Mono", ui-monospace, Menlo, monospace;
  cursor: default;
}

#scene {
  position: fixed;
  inset: 0;
  display: block;
  width: 100%;
  height: 100%;
}

#ui {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10;
}

#hud {
  position: absolute;
  top: 28px;
  left: 32px;
}

.hud-title {
  font-size: 26px;
  letter-spacing: 0.42em;
  font-weight: 600;
  text-shadow: 0 0 18px rgba(111, 227, 255, 0.55);
}

.hud-sub {
  margin-top: 6px;
  font-size: 12px;
  letter-spacing: 0.22em;
  opacity: 0.6;
  text-transform: uppercase;
}

#hint {
  position: absolute;
  bottom: 26px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 12px;
  letter-spacing: 0.12em;
  opacity: 0.55;
  white-space: nowrap;
}

/* Background music controls */
#audio-panel {
  position: absolute;
  top: 28px;
  right: 32px;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  background: rgba(8, 14, 26, 0.58);
  border: 1px solid rgba(255, 244, 232, 0.18);
  border-radius: 6px;
  box-shadow: 0 12px 36px rgba(2, 4, 10, 0.34);
  backdrop-filter: blur(10px);
  pointer-events: auto;
}

.audio-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 30px;
  height: 30px;
  color: rgba(255, 210, 122, 0.84);
}

.icon-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 30px;
  height: 30px;
  border: 1px solid rgba(255, 244, 232, 0.22);
  border-radius: 50%;
  background: rgba(255, 244, 232, 0.08);
  color: var(--ink);
  cursor: pointer;
  transition: background 0.18s ease, border-color 0.18s ease, transform 0.18s ease;
}

.icon-button:hover,
.icon-button:focus-visible {
  background: rgba(255, 184, 107, 0.16);
  border-color: rgba(255, 210, 122, 0.55);
  outline: none;
  transform: translateY(-1px);
}

#audio-panel.is-awaiting-start #audio-toggle {
  border-color: rgba(255, 210, 122, 0.7);
  animation: audio-start-pulse 1.6s ease-in-out infinite;
}

.icon {
  width: 15px;
  height: 15px;
  display: block;
  fill: currentColor;
}

.icon-pause,
#audio-toggle.is-playing .icon-play {
  display: none;
}

#audio-toggle.is-playing .icon-pause {
  display: block;
}

.icon-speaker .mute-mark {
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
  stroke-linecap: round;
  opacity: 0;
}

#audio-mute.is-muted .mute-mark {
  opacity: 1;
}

#audio-volume {
  width: 92px;
  accent-color: var(--accent-warm);
  cursor: pointer;
}

#audio-volume:focus-visible {
  outline: 1px solid rgba(255, 210, 122, 0.75);
  outline-offset: 3px;
}

@keyframes audio-start-pulse {
  0%, 100% {
    box-shadow: 0 0 0 rgba(255, 184, 107, 0);
  }
  50% {
    box-shadow: 0 0 14px rgba(255, 184, 107, 0.42);
  }
}

/* Inspection panel */
#panel {
  position: fixed;
  top: 0;
  right: 0;
  width: min(420px, 92vw);
  height: 100%;
  padding: 88px 38px 38px;
  background: var(--panel-bg);
  backdrop-filter: blur(14px);
  border-left: 1px solid rgba(111, 227, 255, 0.25);
  box-shadow: -30px 0 80px rgba(0, 0, 0, 0.6);
  z-index: 20;
  transition: transform 0.45s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.45s;
}

#panel.hidden {
  transform: translateX(110%);
  opacity: 0;
  pointer-events: none;
}

#panel-tag {
  font-size: 11px;
  letter-spacing: 0.3em;
  color: var(--accent);
  opacity: 0.8;
}

#panel h2 {
  margin: 10px 0 18px;
  font-size: 24px;
  font-weight: 600;
  letter-spacing: 0.04em;
  line-height: 1.2;
}

#panel p {
  font-size: 14px;
  line-height: 1.7;
  opacity: 0.82;
}

#panel-foot {
  position: absolute;
  bottom: 34px;
  left: 38px;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  opacity: 0.4;
}

#panel-close {
  position: absolute;
  top: 26px;
  right: 28px;
  width: 38px;
  height: 38px;
  border: 1px solid rgba(232, 244, 255, 0.25);
  background: transparent;
  color: var(--ink);
  font-size: 20px;
  border-radius: 50%;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
}

#panel-close:hover {
  background: rgba(111, 227, 255, 0.12);
  border-color: var(--accent);
}

/* Map pin marking the landable island */
#island-pin {
  position: fixed;
  top: 0; left: 0;
  transform: translate(-50%, -100%);
  padding: 0;
  background: none;
  border: none;
  cursor: pointer;
  pointer-events: auto;
  z-index: 15;
  transition: filter 0.2s ease, transform 0.18s cubic-bezier(0.22, 1, 0.36, 1);
  transform-origin: bottom center;
  filter:
    drop-shadow(0 2px 4px var(--pin-shadow))
    drop-shadow(0 0 6px rgba(255, 184, 107, 0.3));
}
#island-pin .pin-svg { display: block; }
#island-pin .pin-svg path {
  fill: var(--pin-shell);
  stroke: var(--pin-rim);
  stroke-width: 1.35;
}
#island-pin .pin-svg circle {
  fill: var(--pin-core);
}
/* Hover (or keyboard focus, or synced from the 3D region) lifts the pin. */
#island-pin:hover,
#island-pin:focus-visible,
#island-pin.is-hot {
  transform: translate(-50%, -100%) scale(1.12);
  filter:
    drop-shadow(0 3px 5px var(--pin-shadow))
    drop-shadow(0 0 12px rgba(255, 184, 107, 0.62));
  outline: none;
}

/* Crossfade overlay between views */
#fade {
  position: fixed;
  inset: 0;
  background: #07050f;
  opacity: 0;
  pointer-events: none;
  z-index: 40;
  transition: opacity 0.65s ease;
}
#fade.show { opacity: 1; }

/* First-person island HUD */
#crosshair {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 10px;
  height: 10px;
  margin: -5px 0 0 -5px;
  border: 1.5px solid rgba(255, 244, 232, 0.7);
  border-radius: 50%;
  box-shadow: 0 0 8px rgba(255, 210, 122, 0.6);
}

#fp-prompt {
  position: absolute;
  bottom: 138px;
  left: 50%;
  transform: translateX(-50%);
  width: max-content;
  max-width: calc(100vw - 36px);
  padding: 12px 22px;
  background: rgba(8, 14, 26, 0.7);
  border: 1px solid rgba(255, 210, 122, 0.4);
  border-radius: 6px;
  font-size: 14px;
  line-height: 1.45;
  letter-spacing: 0.12em;
  color: var(--ink);
  text-align: center;
  text-shadow: 0 0 12px rgba(255, 210, 122, 0.4);
}

#fp-controls {
  position: absolute;
  right: 28px;
  bottom: 28px;
  max-width: min(720px, calc(100vw - 56px));
  padding: 9px 12px;
  background: rgba(8, 14, 26, 0.54);
  border: 1px solid rgba(255, 244, 232, 0.18);
  border-radius: 6px;
  color: rgba(232, 244, 255, 0.72);
  font-size: 10px;
  line-height: 1;
  letter-spacing: 0;
}

#fp-controls:not(.hidden) {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: 10px 14px;
}

.control-item {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  min-height: 28px;
  white-space: nowrap;
}

.control-label {
  color: rgba(232, 244, 255, 0.68);
  letter-spacing: 0.05em;
}

.key {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 20px;
  padding: 0 5px;
  border: 1px solid rgba(255, 244, 232, 0.26);
  border-radius: 4px;
  background: rgba(255, 244, 232, 0.08);
  color: var(--ink);
  font-size: 10px;
  font-weight: 600;
  line-height: 1;
  box-shadow: inset 0 -1px 0 rgba(2, 4, 10, 0.4);
}

.key-wide {
  min-width: 30px;
}

.arrow-keys {
  display: grid;
  grid-template-columns: repeat(3, 18px);
  grid-template-rows: repeat(2, 18px);
  gap: 2px;
}

.arrow-keys .key {
  min-width: 18px;
  width: 18px;
  height: 18px;
  padding: 0;
  font-size: 9px;
}

.key-up { grid-column: 2; grid-row: 1; }
.key-left { grid-column: 1; grid-row: 2; }
.key-down { grid-column: 2; grid-row: 2; }
.key-right { grid-column: 3; grid-row: 2; }

.mouse-hint {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: rgba(232, 244, 255, 0.82);
}

.mouse-icon {
  position: relative;
  width: 13px;
  height: 19px;
  border: 1px solid rgba(255, 244, 232, 0.5);
  border-radius: 8px;
  background: rgba(255, 244, 232, 0.08);
}

.mouse-icon::before {
  content: "";
  position: absolute;
  top: 4px;
  left: 50%;
  width: 2px;
  height: 5px;
  transform: translateX(-50%);
  border-radius: 2px;
  background: rgba(255, 210, 122, 0.72);
}

@media (max-width: 680px) {
  #hint {
    bottom: 72px;
    max-width: calc(100vw - 36px);
    text-align: center;
    white-space: normal;
  }

  #audio-panel {
    top: auto;
    right: auto;
    bottom: 22px;
    left: 18px;
    gap: 6px;
    padding: 7px 8px;
  }

  .audio-mark {
    width: 28px;
    height: 28px;
  }

  .icon-button {
    width: 28px;
    height: 28px;
  }

  #audio-volume {
    width: 78px;
  }

  #fp-controls {
    top: 116px;
    right: 18px;
    bottom: auto;
    max-width: calc(100vw - 36px);
  }

  #fp-prompt {
    bottom: 82px;
  }
}

/* Loader */
#loader {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 22px;
  background: #02040a;
  z-index: 50;
  transition: opacity 0.8s ease;
}

#loader.done {
  opacity: 0;
  pointer-events: none;
}

.loader-ring {
  width: 46px;
  height: 46px;
  border: 2px solid rgba(111, 227, 255, 0.2);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.9s linear infinite;
}

.loader-text {
  font-size: 12px;
  letter-spacing: 0.35em;
  opacity: 0.7;
}

@keyframes spin { to { transform: rotate(360deg); } }

.hidden { display: none; }

