import { chromium } from 'playwright';

const URL = 'http://localhost:5178/?view=island';
const headed = process.env.HEADED === '1';
const browser = await chromium.launch({ headless: !headed });
const ctx = await browser.newContext({ viewport: { width: 1280, height: 800 } });
const page = await ctx.newPage();
const errors = [];
page.on('console', m => { if (m.type() === 'error') errors.push(m.text()); });
page.on('pageerror', e => errors.push('PAGEERROR: ' + e.message));

await page.goto(URL, { waitUntil: 'load' });
await page.waitForTimeout(1500);

const canvas = page.locator('#scene');
await canvas.click();              // request pointer lock
await page.waitForTimeout(400);
const locked = await page.evaluate(() => !!document.pointerLockElement);
console.log('POINTER_LOCK:', locked);
console.log('PROMPT_INIT:', await page.locator('#fp-prompt').textContent());

// Walk: hold ArrowUp and sweep the view, polling the prompt for "Press E".
let reached = false;
for (let i = 0; i < 80 && !reached; i++) {
  await page.keyboard.down('ArrowUp');
  // sweep mouse to change heading a little each tick
  await page.mouse.move(640 + (i % 20) * 8, 400);
  await page.waitForTimeout(120);
  const p = (await page.locator('#fp-prompt').textContent()) || '';
  if (p.includes('Press E')) { reached = true; console.log('REACHED at i=' + i + ' prompt=' + p); }
}
await page.keyboard.up('ArrowUp');

if (!reached) {
  console.log('NOT_REACHED. final prompt=', await page.locator('#fp-prompt').textContent());
  await page.screenshot({ path: '/tmp/ckpt-notreached.png' });
  await browser.close();
  process.exit(2);
}

await page.keyboard.press('KeyE');
await page.waitForTimeout(400);
const panelVisible = await page.locator('#panel').evaluate(el => !el.classList.contains('hidden'));
const offerVisible = await page.locator('#ckpt-offer').isVisible();
const footBefore = await page.locator('#panel-foot').textContent();
console.log('PANEL_OPEN:', panelVisible, 'OFFER_VISIBLE:', offerVisible);
console.log('FOOT_BEFORE:', footBefore);
console.log('TITLE:', await page.locator('#panel-title').textContent());
console.log('EXPLAINER:', (await page.locator('.ckpt-explainer').textContent()).trim().replace(/\s+/g,' '));
await page.screenshot({ path: '/tmp/ckpt-before.png' });

await page.locator('#ckpt-create').click();
await page.waitForTimeout(300);
const doneVisible = await page.locator('#ckpt-done').isVisible();
const offerAfter = await page.locator('#ckpt-offer').isVisible();
const footAfter = await page.locator('#panel-foot').textContent();
console.log('DONE_VISIBLE:', doneVisible, 'OFFER_AFTER:', offerAfter);
console.log('FOOT_AFTER:', footAfter);
await page.screenshot({ path: '/tmp/ckpt-after.png' });

console.log('CONSOLE_ERRORS:', JSON.stringify(errors));
await browser.close();

