import pkg from '/Users/goose-guest/.npm/_npx/e41f203b7505f1fb/node_modules/playwright/index.js';
const { chromium } = pkg;

const URL = 'http://localhost:5178/?view=island';
const browser = await chromium.launch({ headless: false });
const ctx = await browser.newContext({ viewport: { width: 1280, height: 800 } });
const page = await ctx.newPage();
const errors = [];
page.on('console', m => { if (m.type() === 'error') errors.push(m.text()); });
page.on('pageerror', e => errors.push('PAGEERROR: ' + e.message));

await page.goto(URL, { waitUntil: 'load' });
await page.waitForTimeout(1200);

const prompt = () => page.locator('#fp-prompt').textContent();
const isLocked = () => page.evaluate(() => !!document.pointerLockElement);

async function ensureLock() {
  if (!(await isLocked())) {
    await page.locator('#scene').click();
    await page.waitForTimeout(250);
  }
}
await ensureLock();
console.log('LOCK_AFTER_CLICK:', await isLocked(), '| prompt:', await prompt());

// Walk forward continuously while slowly rotating, so we spiral across the
// whole island. Poll the prompt; stop when an artifact comes in range.
let reached = false, finalPrompt = '';
let mx = 300;
await page.keyboard.down('ArrowUp');
for (let i = 0; i < 140 && !reached; i++) {
  await ensureLock();
  // Steady small rightward mouse delta -> steady turn.
  mx += 12; if (mx > 980) mx = 300;
  await page.mouse.move(mx, 400);
  await page.waitForTimeout(90);
  const p = (await prompt()) || '';
  finalPrompt = p;
  if (i % 20 === 0) console.log(`i=${i} locked=${await isLocked()} prompt="${p}"`);
  if (p.includes('Press E')) { reached = true; console.log(`REACHED i=${i} prompt="${p}"`); }
}
await page.keyboard.up('ArrowUp');

if (!reached) {
  console.log('NOT_REACHED final="' + finalPrompt + '"');
  await page.screenshot({ path: '/tmp/ckpt-notreached.png' });
  await browser.close();
  process.exit(2);
}

await page.keyboard.press('KeyE');
await page.waitForTimeout(400);
console.log('--- BEFORE CREATE ---');
console.log('PANEL_OPEN:', await page.locator('#panel').evaluate(el => !el.classList.contains('hidden')));
console.log('OFFER_VISIBLE:', await page.locator('#ckpt-offer').isVisible());
console.log('DONE_VISIBLE:', await page.locator('#ckpt-done').isVisible());
console.log('TITLE:', await page.locator('#panel-title').textContent());
console.log('Q:', await page.locator('.ckpt-q').textContent());
console.log('EXPLAINER:', (await page.locator('.ckpt-explainer').textContent()).trim().replace(/\s+/g, ' '));
console.log('FOOT_BEFORE:', await page.locator('#panel-foot').textContent());
await page.screenshot({ path: '/tmp/ckpt-before.png' });

await page.locator('#ckpt-create').click();
await page.waitForTimeout(300);
console.log('--- AFTER CREATE ---');
console.log('OFFER_VISIBLE:', await page.locator('#ckpt-offer').isVisible());
console.log('DONE_VISIBLE:', await page.locator('#ckpt-done').isVisible());
console.log('DONE_TITLE:', await page.locator('.ckpt-done-title').textContent());
console.log('DONE_SUB:', await page.locator('.ckpt-done-sub').textContent());
console.log('FOOT_AFTER:', await page.locator('#panel-foot').textContent());
await page.screenshot({ path: '/tmp/ckpt-after.png' });

console.log('CONSOLE_ERRORS:', JSON.stringify(errors));
await browser.close();

