import pkg from '/Users/goose-guest/.npm/_npx/e41f203b7505f1fb/node_modules/playwright/index.js';
const { chromium } = pkg;
const browser = await chromium.launch({ headless: true });
const page = await (await browser.newContext()).newPage();
await page.goto('http://localhost:5178/?view=island', { waitUntil: 'load' });
await page.waitForTimeout(800);
// #ckpt-done starts with class="hidden". With the specificity fix it must
// resolve to display:none (previously the ID rule forced display:flex).
const r = await page.evaluate(() => {
  const done = document.getElementById('ckpt-done');
  const offer = document.getElementById('ckpt-offer');
  return {
    doneHasHidden: done.classList.contains('hidden'),
    doneDisplay: getComputedStyle(done).display,
    offerDisplay: getComputedStyle(offer).display,
  };
});
console.log(JSON.stringify(r, null, 2));
await browser.close();

