const page = await ctx.newPage();
const errors = [];
page.on('console', m => { if (m.type() === 'error') errors.push(m.text()); });
page.on('pageerror', e => errors.push('PAGEERROR: ' + e.message));

await page.goto(URL, { waitUntil: 'load' });
await page.bringToFront();
await page.waitForTimeout(1200);

const prompt = () => page.locator('#fp-prompt').textContent();
const isLocked = () => page.evaluate(() => !!document.pointerLockElement);

async function ensureLock() {
  for (let k = 0; k < 5 && !(await isLocked()); k++) {
    await page.bringToFront();
    await page.mouse.click(640, 400);
    await page.waitForTimeout(250);
  }
}
await ensureLock();
console.log('LOCK_AFTER_CLICK:', await isLocked(), '| prompt:', await prompt());

// Walk forward continuously while slowly rotating, so we spiral across the
// whole island. Poll the prompt; stop when an artifact comes in range.
let reached = false, finalPrompt = '';
